class Solution {
public:
    long long minimumCost(string s) {
        long long n = s.size();
        long long cost = 0;
        long long ones = 0;
        for (int i = 0; i < n; i++) {
            if (s[i] == '1') {
                ones++;
            }
            if (i == n - 1 || s[i + 1] != s[i]) {
                cost += min(ones, n - ones);
                ones = 0;
            }
        }
        return cost;
    }
};
```

